  9→#[derive(Debug, Clone, PartialEq, Eq)]
 10→pub struct GgufRuntimeDevice {
 11→    pub index: usize,
 12→    pub name: String,
 13→    pub description: String,
 14→    pub backend: String,
 15→    pub memory_total_bytes: u64,
 16→    pub memory_free_bytes: u64,
 17→}
 18→
 19→/// Summary of GPU backends actually available to GGUF inference at runtime.
 20→#[derive(Debug, Clone, Default, PartialEq, Eq)]
 21→pub struct GgufRuntimeSupport {
 22→    pub devices: Vec<GgufRuntimeDevice>,
 23→    pub has_metal: bool,
 24→    pub has_cuda: bool,
 25→    pub has_vulkan: bool,
 26→}
 27→
 28→impl GgufRuntimeSupport {
 29→    #[must_use]
 30→    pub fn from_devices(devices: Vec<GgufRuntimeDevice>) -> Self {
 31→        let has_metal = devices
 32→            .iter()
 33→            .any(|device| device.backend.eq_ignore_ascii_case("metal"));
 34→        let has_cuda = devices
 35→            .iter()
 36→            .any(|device| device.backend.eq_ignore_ascii_case("cuda"));
 37→        let has_vulkan = devices
 38→            .iter()
 39→            .any(|device| device.backend.eq_ignore_ascii_case("vulkan"));
 40→
 41→        Self {
 42→            devices,
 43→            has_metal,
 44→            has_cuda,
 45→            has_vulkan,
 46→        }
 47→    }
 48→}
 49→
 50→/// Detect GGUF runtime devices and summarize available acceleration backends.
 51→#[must_use]
 52→pub fn detect_runtime_support() -> GgufRuntimeSupport {
 53→    let backend_guard = match LlamaBackend::init() {
 54→        Ok(backend) => Some(backend),
 55→        Err(LlamaCppError::BackendAlreadyInitialized) => None,
 56→        Err(error) => {
 57→            debug!(%error, "failed to initialize llama backend for GGUF device probe");
 58→            return GgufRuntimeSupport::default();
 59→        },
 60→    };
 61→
 62→    let devices = list_llama_ggml_backend_devices()
 63→        .into_iter()
 64→        .filter(|device| !device.backend.eq_ignore_ascii_case("cpu"))
 65→        .map(|device| GgufRuntimeDevice {
 66→            index: device.index,
 67→            name: device.name,
 68→            description: device.description,
 69→            backend: device.backend,
 70→            memory_total_bytes: device.memory_total as u64,
 71→            memory_free_bytes: device.memory_free as u64,
 72→        })
 73→        .collect();
 74→
 75→    drop(backend_guard);
 76→
 77→    GgufRuntimeSupport::from_devices(devices)
 78→}
