  1→//! System information detection for local LLM inference.
  2→//!
  3→//! Detects available RAM and GPU capabilities to suggest appropriate models.
  4→
  5→use {
  6→    crate::local_gguf::runtime_devices::{self, GgufRuntimeDevice},
  7→    sysinfo::System,
  8→};
  9→
 10→/// System information for model selection.
 11→#[derive(Debug, Clone)]
 12→pub struct SystemInfo {
 13→    /// Total system RAM in bytes.
 14→    pub total_ram_bytes: u64,
 15→    /// Available (free) RAM in bytes.
 16→    pub available_ram_bytes: u64,
 17→    /// GGUF devices discovered via llama.cpp runtime probing.
 18→    pub gguf_devices: Vec<GgufRuntimeDevice>,
 19→    /// Whether Metal GPU acceleration is available (macOS).
 20→    pub has_metal: bool,
 21→    /// Whether CUDA GPU acceleration is available (NVIDIA).
 22→    pub has_cuda: bool,
 23→    /// Whether Vulkan GPU acceleration is available.
 24→    pub has_vulkan: bool,
 25→    /// Whether running on Apple Silicon (M1/M2/M3/etc).
 26→    pub is_apple_silicon: bool,
 27→}
 28→
 29→impl SystemInfo {
 30→    /// Detect system information.
 31→    pub fn detect() -> Self {
 32→        let sys = System::new_all();
 33→
 34→        let (total_ram_bytes, available_ram_bytes) = {
 35→            let total = sys.total_memory();
 36→            let available = sys.available_memory();
 37→            if total > 0 {
 38→                (total, available)
 39→            } else if let Some((fallback_total, fallback_available)) = read_proc_meminfo() {
 40→                (fallback_total, fallback_available)
 41→            } else {
 42→                (total, available)
 43→            }
 44→        };
 45→        let runtime = runtime_devices::detect_runtime_support();
 46→
 47→        // Apple Silicon detection: macOS + ARM architecture
 48→        let is_apple_silicon = cfg!(target_os = "macos") && cfg!(target_arch = "aarch64");
 49→
 50→        Self {
 51→            total_ram_bytes,
 52→            available_ram_bytes,
 53→            gguf_devices: runtime.devices,
 54→            has_metal: runtime.has_metal,
 55→            has_cuda: runtime.has_cuda,
 56→            has_vulkan: runtime.has_vulkan,
 57→            is_apple_silicon,
 58→        }
 59→    }
 60→
 61→    /// Total RAM in gigabytes.
 62→    #[must_use]
 63→    pub fn total_ram_gb(&self) -> u32 {
 64→        (self.total_ram_bytes / (1024 * 1024 * 1024)) as u32
 65→    }
 66→
 67→    /// Available RAM in gigabytes.
 68→    #[must_use]
 69→    pub fn available_ram_gb(&self) -> u32 {
 70→        (self.available_ram_bytes / (1024 * 1024 * 1024)) as u32
 71→    }
 72→
 73→    /// Memory tier for model suggestions.
 74→    #[must_use]
 75→    pub fn memory_tier(&self) -> MemoryTier {
 76→        let gb = self.total_ram_gb();
 77→        if gb >= 32 {
 78→            MemoryTier::Large
 79→        } else if gb >= 16 {
 80→            MemoryTier::Medium
 81→        } else if gb >= 8 {
 82→            MemoryTier::Small
 83→        } else {
 84→            MemoryTier::Tiny
 85→        }
 86→    }
 87→
 88→    /// Whether GPU acceleration is available.
 89→    #[must_use]
 90→    pub fn has_gpu(&self) -> bool {
 91→        !self.gguf_devices.is_empty()
 92→    }
 93→}
 94→
 95→/// Memory tier for model recommendations.
 96→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 97→pub enum MemoryTier {
 98→    /// 4GB or less — only very small models
 99→    Tiny,
100→    /// 8GB — small 1-3B models
101→    Small,
102→    /// 16GB — medium 7-14B models
103→    Medium,
104→    /// 32GB+ — larger 14B+ models
105→    Large,
106→}
107→
108→impl std::fmt::Display for MemoryTier {
109→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
110→        match self {
111→            MemoryTier::Tiny => write!(f, "tiny (4GB)"),
112→            MemoryTier::Small => write!(f, "small (8GB)"),
113→            MemoryTier::Medium => write!(f, "medium (16GB)"),
114→            MemoryTier::Large => write!(f, "large (32GB+)"),
115→        }
116→    }
117→}
118→
119→/// Parse `/proc/meminfo` as a fallback when `sysinfo` returns 0 (common in
120→/// Docker containers with restrictive cgroup settings).
121→///
122→/// Returns `(total_bytes, available_bytes)` or `None` if the file is absent or
123→/// unparseable.
124→fn read_proc_meminfo() -> Option<(u64, u64)> {
125→    let content = std::fs::read_to_string("/proc/meminfo").ok()?;
126→    let mut total_kb: Option<u64> = None;
127→    let mut available_kb: Option<u64> = None;
128→
129→    for line in content.lines() {
130→        if let Some(rest) = line.strip_prefix("MemTotal:") {
131→            total_kb = parse_meminfo_kb(rest);
132→        } else if let Some(rest) = line.strip_prefix("MemAvailable:") {
133→            available_kb = parse_meminfo_kb(rest);
134→        }
135→        if total_kb.is_some() && available_kb.is_some() {
136→            break;
137→        }
138→    }
139→
140→    let total = total_kb? * 1024;
141→    let available = available_kb.unwrap_or(0) * 1024;
142→    Some((total, available))
143→}
144→
145→/// Parse a `/proc/meminfo` value line like `"   16384 kB"` into kilobytes.
146→fn parse_meminfo_kb(value: &str) -> Option<u64> {
147→    value.split_whitespace().next()?.parse::<u64>().ok()
148→}
