 88→/// Local GGUF LLM provider.
 89→pub struct LocalGgufProvider {
 90→    backend: Arc<SendSyncBackend>,
 91→    model: Arc<Mutex<LlamaModel>>,
 92→    model_id: String,
 93→    model_def: Option<&'static GgufModelDef>,
 94→    context_size: u32,
 95→    temperature: f32,
 96→}
 97→
 98→impl LocalGgufProvider {
 99→    /// Create a new provider with an already-loaded model.
100→    fn new_with_model(
101→        backend: LlamaBackend,
102→        model: LlamaModel,
103→        model_id: String,
104→        model_def: Option<&'static GgufModelDef>,
105→        context_size: u32,
106→        temperature: f32,
107→    ) -> Self {
108→        info!(
109→            model = %model_id,
110→            context_size,
111→            "local GGUF provider initialized"
112→        );
113→        Self {
114→            backend: Arc::new(SendSyncBackend(backend)),
115→            model: Arc::new(Mutex::new(model)),
116→            model_id,
117→            model_def,
118→            context_size,
119→            temperature,
120→        }
121→    }
122→
123→    /// Load a provider from configuration.
124→    ///
125→    /// This will download the model if needed.
126→    pub async fn from_config(config: LocalGgufConfig) -> Result<Self> {
127→        let load_start = Instant::now();
128→
129→        // Resolve model path
130→        let (model_path, model_def) = if let Some(path) = config.model_path {
131→            // User provided direct path
132→            if !path.exists() {
133→                bail!("model file not found: {}", path.display());
134→            }
135→            (path, find_model(&config.model_id))
136→        } else {
137→            // Look up in registry and download if needed
138→            let Some(def) = find_model(&config.model_id) else {
139→                bail!(
140→                    "unknown model '{}'. Use model_path for custom GGUF files.",
141→                    config.model_id
142→                );
143→            };
144→
145→            // MLX models require the MLX backend (Python mlx_lm), not llama.cpp
146→            if matches!(def.backend, models::ModelBackend::Mlx) {
147→                bail!(
148→                    "Model '{}' requires the MLX backend which is not available in this context. \
149→                     MLX models need Python with mlx_lm installed. \
150→                     Please select a GGUF model instead (e.g., 'llama-3.2-1b-q4_k_m').",
151→                    config.model_id
152→                );
153→            }
154→
155→            let path = models::ensure_model(def, &config.cache_dir).await?;
156→            (path, Some(def))
157→        };
158→
159→        // Determine context size
160→        let context_size = config
161→            .context_size
162→            .or_else(|| model_def.map(|d| d.context_window))
163→            .unwrap_or(8192);
164→
165→        // Load the model
166→        debug!(model = %config.model_id, "initializing llama backend");
167→        let backend = LlamaBackend::init().context("initializing llama backend")?;
168→
169→        let mut model_params = LlamaModelParams::default();
170→
171→        // GPU offloading
172→        if config.gpu_layers > 0 {
173→            model_params = model_params.with_n_gpu_layers(config.gpu_layers);
174→            info!(gpu_layers = config.gpu_layers, "GPU offloading enabled");
175→        }
176→
177→        debug!(
178→            path = %model_path.display(),
179→            model = %config.model_id,
180→            "loading GGUF model file"
181→        );
182→        let model = LlamaModel::load_from_file(&backend, &model_path, &model_params)
183→            .map_err(|e| anyhow::anyhow!("failed to load GGUF model: {e}"))?;
184→
185→        let load_duration = load_start.elapsed();
186→
187→        info!(
188→            path = %model_path.display(),
189→            model = %config.model_id,
190→            context_size,
191→            load_duration_secs = load_duration.as_secs_f64(),
192→            "loaded local GGUF model"
193→        );
194→
195→        // Record model load metrics
196→        #[cfg(feature = "metrics")]
197→        {
198→            // Use a local-llm specific metric for model loading
199→            histogram!(
200→                "moltis_local_llm_model_load_duration_seconds",
201→                labels::MODEL => config.model_id.clone()
202→            )
203→            .record(load_duration.as_secs_f64());
204→
205→            gauge!(
206→                "moltis_local_llm_models_loaded",
207→                labels::MODEL => config.model_id.clone()
208→            )
209→            .increment(1.0);
210→        }
211→
212→        Ok(Self::new_with_model(
213→            backend,
214→            model,
215→            config.model_id,
216→            model_def,
217→            context_size,
218→            config.temperature,
219→        ))
220→    }
221→
222→    /// Get the chat template hint for this model.
223→    fn chat_template(&self) -> ChatTemplateHint {
224→        self.model_def
225→            .map(|d| d.chat_template)
226→            .unwrap_or(ChatTemplateHint::Auto)
227→    }
228→
229→    /// Generate text synchronously (called from blocking context).
230→    ///
231→    /// When `tool_names` is non-empty, a lazy GBNF grammar sampler constrains
232→    /// the output to valid `tool_call` fenced blocks.
233→    fn generate_sync(
234→        &self,
235→        prompt: &str,
236→        max_tokens: u32,
237→        tool_names: &[&str],
238→    ) -> Result<(String, u32, u32)> {
239→        let generation_start = Instant::now();
240→        let model = self.model.blocking_lock();
241→        let backend = &self.backend.0;
242→
243→        // Batch size for processing (default in llama.cpp is 2048, we use 512 for safety)
244→        let batch_size: usize = 512;
245→
246→        // Create context
247→        let ctx_params = LlamaContextParams::default()
248→            .with_n_ctx(NonZeroU32::new(self.context_size))
249→            .with_n_batch(batch_size as u32);
250→        let mut ctx = model
251→            .new_context(backend, ctx_params)
252→            .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
253→
254→        // Tokenize prompt
255→        let tokens = model
256→            .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
257→            .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
258→
259→        let input_tokens = tokens.len() as u32;
260→        debug!(input_tokens, batch_size, "tokenized prompt");
261→
262→        if tokens.is_empty() {
263→            bail!("empty token sequence");
264→        }
265→
266→        // Process prompt in batches to avoid exceeding n_batch
267→        debug!(
268→            num_chunks = tokens.len().div_ceil(batch_size),
269→            "processing prompt"
270→        );
271→        let mut batch = LlamaBatch::new(batch_size, 1);
272→        for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
273→            batch.clear();
274→            let chunk_start = chunk_idx * batch_size;
275→            let is_last_chunk = chunk_start + chunk.len() == tokens.len();
276→
277→            for (i, &token) in chunk.iter().enumerate() {
278→                let pos = (chunk_start + i) as i32;
279→                // Only compute logits for the very last token
280→                let is_last = is_last_chunk && i == chunk.len() - 1;
281→                batch
282→                    .add(token, pos, &[0], is_last)
283→                    .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
284→            }
285→
286→            ctx.decode(&mut batch)
287→                .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
288→        }
289→
290→        let prompt_eval_time = generation_start.elapsed();
291→        debug!(
292→            prompt_eval_secs = prompt_eval_time.as_secs_f64(),
293→            "prompt evaluation complete"
294→        );
295→
296→        // Set up sampler chain.
297→        // When tools are available, add a lazy grammar sampler that activates
298→        // when the model emits ` ``` ` (start of a fenced block).
299→        let mut samplers: Vec<LlamaSampler> = Vec::new();
300→
301→        if let Some(grammar_str) = tool_grammar::build_tool_call_grammar(tool_names) {
302→            match LlamaSampler::grammar_lazy(&model, &grammar_str, "root", ["```tool_call"], &[]) {
303→                Ok(grammar_sampler) => {
304→                    debug!("grammar-constrained sampling enabled for tool calls");
305→                    samplers.push(grammar_sampler);
306→                },
307→                Err(e) => {
308→                    warn!(%e, "failed to create grammar sampler, falling back to unconstrained");
309→                },
310→            }
311→        }
312→
313→        samplers.push(LlamaSampler::temp(self.temperature));
314→        samplers.push(LlamaSampler::dist(42)); // Seed
315→
316→        let mut sampler = LlamaSampler::chain_simple(samplers);
317→
318→        // Generate tokens
319→        let token_gen_start = Instant::now();
320→        let mut output_tokens = Vec::new();
321→        let mut pos = tokens.len() as i32;
322→        let eos_token = model.token_eos();
323→
324→        for _ in 0..max_tokens {
325→            // Sample from the last position in the batch
326→            let token = sampler.sample(&ctx, batch.n_tokens() - 1);
327→
328→            if token == eos_token {
329→                debug!("reached EOS token");
330→                break;
331→            }
332→
333→            output_tokens.push(token);
334→            sampler.accept(token);
335→
336→            // Decode next token
337→            batch.clear();
338→            batch
339→                .add(token, pos, &[0], true)
340→                .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
341→            ctx.decode(&mut batch)
342→                .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
343→
344→            pos += 1;
345→        }
346→
347→        let token_gen_duration = token_gen_start.elapsed();
348→        let total_duration = generation_start.elapsed();
349→        let output_token_count = output_tokens.len() as u32;
350→
351→        // Calculate tokens per second
352→        let tokens_per_sec = if token_gen_duration.as_secs_f64() > 0.0 {
353→            output_token_count as f64 / token_gen_duration.as_secs_f64()
354→        } else {
355→            0.0
356→        };
357→
358→        debug!(
359→            output_tokens = output_token_count,
360→            generation_secs = token_gen_duration.as_secs_f64(),
361→            total_secs = total_duration.as_secs_f64(),
362→            tokens_per_sec = format!("{:.1}", tokens_per_sec),
363→            "generation complete"
364→        );
365→
366→        // Detokenize output
367→        let output_text = detokenize(&model, &output_tokens)?;
368→
369→        Ok((output_text, input_tokens, output_token_count))
370→    }
371→}
372→
373→/// Detokenize a sequence of tokens into a string.
374→fn detokenize(model: &LlamaModel, tokens: &[LlamaToken]) -> Result<String> {
375→    let mut decoder = encoding_rs::UTF_8.new_decoder();
376→    let mut output = String::new();
377→    for &token in tokens {
378→        let piece = model
379→            .token_to_piece(token, &mut decoder, true, None)
380→            .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
381→        output.push_str(&piece);
382→    }
383→    Ok(output)
384→}
385→
386→#[async_trait]
387→impl LlmProvider for LocalGgufProvider {
388→    fn name(&self) -> &str {
389→        "local-llm"
390→    }
391→
392→    fn id(&self) -> &str {
393→        &self.model_id
394→    }
395→
396→    fn context_window(&self) -> u32 {
397→        self.context_size
398→    }
399→
400→    fn supports_tools(&self) -> bool {
401→        true
402→    }
403→
404→    async fn complete(
405→        &self,
406→        messages: &[ChatMessage],
407→        tools: &[serde_json::Value],
408→    ) -> Result<CompletionResponse> {
409→        let prompt = format_messages(messages, self.chat_template());
410→        let max_tokens = 4096u32;
411→
412→        // Extract tool names for grammar constraint.
413→        let tool_names: Vec<String> = tools
414→            .iter()
415→            .filter_map(|t| t["name"].as_str().map(String::from))
416→            .collect();
417→
418→        // Clone what we need for the blocking task
419→        let backend = Arc::clone(&self.backend);
420→        let model = Arc::clone(&self.model);
421→        let context_size = self.context_size;
422→        let temperature = self.temperature;
423→        let model_id = self.model_id.clone();
424→        let model_def = self.model_def;
425→
426→        // Run generation in blocking context
427→        let (text, input_tokens, output_tokens) = tokio::task::spawn_blocking(move || {
428→            let tool_name_refs: Vec<&str> = tool_names.iter().map(String::as_str).collect();
429→            let provider = LocalGgufProvider {
430→                backend,
431→                model,
432→                model_id,
433→                model_def,
434→                context_size,
435→                temperature,
436→            };
437→            provider.generate_sync(&prompt, max_tokens, &tool_name_refs)
438→        })
439→        .await
440→        .context("generation task panicked")??;
441→
442→        // Parse tool calls from the generated text.
443→        let (parsed_calls, remaining_text) =
444→            moltis_agents::tool_parsing::parse_tool_calls_from_text(&text);
445→
446→        let tool_calls: Vec<ToolCall> = parsed_calls
447→            .into_iter()
448→            .map(|tc| ToolCall {
449→                id: tc.id,
450→                name: tc.name,
451→                arguments: tc.arguments,
452→            })
453→            .collect();
454→
455→        let display_text = if tool_calls.is_empty() {
456→            Some(text)
457→        } else {
458→            remaining_text.filter(|s| !s.is_empty())
459→        };
460→
461→        Ok(CompletionResponse {
462→            text: display_text,
463→            tool_calls,
464→            usage: Usage {
465→                input_tokens,
466→                output_tokens,
467→                ..Default::default()
468→            },
469→        })
470→    }
471→
472→    fn stream(
473→        &self,
474→        messages: Vec<ChatMessage>,
475→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
476→        let prompt = format_messages(&messages, self.chat_template());
477→        let max_tokens = 4096u32;
478→
479→        let backend = Arc::clone(&self.backend);
480→        let model = Arc::clone(&self.model);
481→        let context_size = self.context_size;
482→        let temperature = self.temperature;
483→
484→        Box::pin(async_stream::stream! {
485→            let (tx, mut rx) = tokio::sync::mpsc::channel::<StreamEvent>(32);
486→
487→            // Spawn blocking generation task
488→            let handle = tokio::task::spawn_blocking(move || {
489→                stream_generate_sync(
490→                    &backend.0,
491→                    &model,
492→                    &prompt,
493→                    max_tokens,
494→                    context_size,
495→                    temperature,
496→                    tx,
497→                )
498→            });
499→
500→            // Yield events from the channel
501→            while let Some(event) = rx.recv().await {
502→                let is_done = matches!(event, StreamEvent::Done(_) | StreamEvent::Error(_));
503→                yield event;
504→                if is_done {
505→                    break;
506→                }
507→            }
508→
509→            // Wait for the blocking task to complete
510→            if let Err(e) = handle.await {
511→                warn!("generation task error: {e}");
512→            }
513→        })
514→    }
515→}
516→
517→/// Streaming generation in a blocking context.
518→fn stream_generate_sync(
519→    backend: &LlamaBackend,
520→    model: &Mutex<LlamaModel>,
521→    prompt: &str,
522→    max_tokens: u32,
523→    context_size: u32,
524→    temperature: f32,
525→    tx: tokio::sync::mpsc::Sender<StreamEvent>,
526→) {
527→    let generation_start = Instant::now();
528→    // Batch size for processing (default in llama.cpp is 2048, we use 512 for safety)
529→    let batch_size: usize = 512;
530→
531→    let result = (|| -> Result<(u32, u32)> {
532→        let model = model.blocking_lock();
533→
534→        // Create context
535→        let ctx_params = LlamaContextParams::default()
536→            .with_n_ctx(NonZeroU32::new(context_size))
537→            .with_n_batch(batch_size as u32);
538→        let mut ctx = model
539→            .new_context(backend, ctx_params)
540→            .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
541→
542→        // Tokenize prompt
543→        let tokens = model
544→            .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
545→            .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
546→
547→        let input_tokens = tokens.len() as u32;
548→        debug!(input_tokens, "tokenized prompt for streaming");
549→
550→        if tokens.is_empty() {
551→            bail!("empty token sequence");
552→        }
553→
554→        // Process prompt in batches to avoid exceeding n_batch
555→        let mut batch = LlamaBatch::new(batch_size, 1);
556→        for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
557→            batch.clear();
558→            let chunk_start = chunk_idx * batch_size;
559→            let is_last_chunk = chunk_start + chunk.len() == tokens.len();
560→
561→            for (i, &token) in chunk.iter().enumerate() {
562→                let pos = (chunk_start + i) as i32;
563→                // Only compute logits for the very last token
564→                let is_last = is_last_chunk && i == chunk.len() - 1;
565→                batch
566→                    .add(token, pos, &[0], is_last)
567→                    .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
568→            }
569→
570→            ctx.decode(&mut batch)
571→                .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
572→        }
573→
574→        let prompt_eval_time = generation_start.elapsed();
575→        debug!(
576→            prompt_eval_secs = prompt_eval_time.as_secs_f64(),
577→            "prompt evaluation complete, starting token generation"
578→        );
579→
580→        // Set up sampler chain: temperature -> random distribution
581→        let mut sampler =
582→            LlamaSampler::chain_simple([LlamaSampler::temp(temperature), LlamaSampler::dist(42)]);
583→
584→        // Generate tokens
585→        let token_gen_start = Instant::now();
586→        let mut first_token_time: Option<std::time::Duration> = None;
587→        let mut output_tokens = 0u32;
588→        let mut pos = tokens.len() as i32;
589→        let eos_token = model.token_eos();
590→        let mut decoder = encoding_rs::UTF_8.new_decoder();
591→
592→        for _ in 0..max_tokens {
593→            // Sample from the last position in the batch
594→            let token = sampler.sample(&ctx, batch.n_tokens() - 1);
595→
596→            if token == eos_token {
597→                debug!("reached EOS token");
598→                break;
599→            }
600→
601→            output_tokens += 1;
602→
603→            // Record time to first token
604→            if first_token_time.is_none() {
605→                let ttft = generation_start.elapsed();
606→                first_token_time = Some(ttft);
607→                debug!(ttft_secs = ttft.as_secs_f64(), "time to first token");
608→
609→                #[cfg(feature = "metrics")]
610→                histogram!(llm_metrics::TIME_TO_FIRST_TOKEN_SECONDS).record(ttft.as_secs_f64());
611→            }
612→
613→            sampler.accept(token);
614→
615→            // Detokenize and send
616→            let piece = model
617→                .token_to_piece(token, &mut decoder, true, None)
618→                .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
619→
620→            if tx.blocking_send(StreamEvent::Delta(piece)).is_err() {
621→                // Receiver dropped, stop generation
622→                debug!("receiver dropped, stopping generation");
623→                break;
624→            }
625→
626→            // Decode next token
627→            batch.clear();
628→            batch
629→                .add(token, pos, &[0], true)
630→                .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
631→            ctx.decode(&mut batch)
632→                .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
633→
634→            pos += 1;
635→        }
636→
637→        let token_gen_duration = token_gen_start.elapsed();
638→        let total_duration = generation_start.elapsed();
639→
640→        // Calculate and log tokens per second
641→        let tokens_per_sec = if token_gen_duration.as_secs_f64() > 0.0 {
642→            output_tokens as f64 / token_gen_duration.as_secs_f64()
643→        } else {
644→            0.0
645→        };
646→
647→        debug!(
648→            output_tokens,
649→            generation_secs = token_gen_duration.as_secs_f64(),
650→            total_secs = total_duration.as_secs_f64(),
651→            tokens_per_sec = format!("{:.1}", tokens_per_sec),
652→            "streaming generation complete"
653→        );
654→
655→        #[cfg(feature = "metrics")]
656→        if tokens_per_sec > 0.0 {
657→            histogram!(llm_metrics::TOKENS_PER_SECOND).record(tokens_per_sec);
658→        }
659→
660→        Ok((input_tokens, output_tokens))
661→    })();
662→
663→    match result {
664→        Ok((input_tokens, output_tokens)) => {
665→            let _ = tx.blocking_send(StreamEvent::Done(Usage {
666→                input_tokens,
667→                output_tokens,
668→                ..Default::default()
669→            }));
670→        },
671→        Err(e) => {
672→            warn!(error = %e, "streaming generation failed");
673→            let _ = tx.blocking_send(StreamEvent::Error(e.to_string()));
674→        },
675→    }
676→}
