678→/// Lazy-loading wrapper for LocalGgufProvider.
679→///
680→/// The actual model is loaded on first use (complete/stream call).
681→/// This allows registration at startup without blocking on model download.
682→pub struct LazyLocalGgufProvider {
683→    config: LocalGgufConfig,
684→    inner: tokio::sync::RwLock<Option<LocalGgufProvider>>,
685→}
686→
687→impl LazyLocalGgufProvider {
688→    /// Create a new lazy provider with the given config.
689→    pub fn new(config: LocalGgufConfig) -> Self {
690→        Self {
691→            config,
692→            inner: tokio::sync::RwLock::new(None),
693→        }
694→    }
695→
696→    /// Ensure the inner provider is loaded, loading it if necessary.
697→    async fn ensure_loaded(&self) -> Result<()> {
698→        // Check if already loaded (read lock is cheaper)
699→        {
700→            let guard = self.inner.read().await;
701→            if guard.is_some() {
702→                return Ok(());
703→            }
704→        }
705→
706→        // Need to load - acquire write lock
707→        let mut guard = self.inner.write().await;
708→
709→        // Double-check after acquiring write lock
710→        if guard.is_some() {
711→            return Ok(());
712→        }
713→
714→        info!(model = %self.config.model_id, "loading local GGUF model on first use");
715→        let provider = LocalGgufProvider::from_config(self.config.clone()).await?;
716→        *guard = Some(provider);
717→        Ok(())
718→    }
719→}
720→
721→#[async_trait]
722→impl LlmProvider for LazyLocalGgufProvider {
723→    fn name(&self) -> &str {
724→        "local-llm"
725→    }
726→
727→    fn id(&self) -> &str {
728→        &self.config.model_id
729→    }
730→
731→    fn context_window(&self) -> u32 {
732→        // Use model definition if available, otherwise default
733→        find_model(&self.config.model_id)
734→            .map(|d| d.context_window)
735→            .unwrap_or(8192)
736→    }
737→
738→    fn supports_tools(&self) -> bool {
739→        true
740→    }
741→
742→    async fn complete(
743→        &self,
744→        messages: &[ChatMessage],
745→        tools: &[serde_json::Value],
746→    ) -> Result<CompletionResponse> {
747→        self.ensure_loaded().await?;
748→        let guard = self.inner.read().await;
749→        let provider = guard
750→            .as_ref()
751→            .ok_or_else(|| anyhow::anyhow!("provider should be loaded after ensure_loaded"))?;
752→        provider.complete(messages, tools).await
753→    }
754→
755→    fn stream(
756→        &self,
757→        messages: Vec<ChatMessage>,
758→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
759→        Box::pin(async_stream::stream! {
760→            if let Err(e) = self.ensure_loaded().await {
761→                yield StreamEvent::Error(format!("failed to load model: {e}"));
762→                return;
763→            }
764→
765→            let guard = self.inner.read().await;
766→            let Some(provider) = guard.as_ref() else {
767→                yield StreamEvent::Error("provider should be loaded after ensure_loaded".into());
768→                return;
769→            };
770→
771→            // We need to create a stream from the inner provider
772→            // But we can't hold the guard across the stream, so we need to
773→            // copy the necessary state
774→            let backend = Arc::clone(&provider.backend);
775→            let model = Arc::clone(&provider.model);
776→            let context_size = provider.context_size;
777→            let temperature = provider.temperature;
778→            let chat_template = provider.chat_template();
779→
780→            drop(guard);
781→
782→            let prompt = format_messages(&messages, chat_template);
783→            let max_tokens = 4096u32;
784→
785→            let (tx, mut rx) = tokio::sync::mpsc::channel::<StreamEvent>(32);
786→
787→            let handle = tokio::task::spawn_blocking(move || {
788→                stream_generate_sync(
789→                    &backend.0,
790→                    &model,
791→                    &prompt,
792→                    max_tokens,
793→                    context_size,
794→                    temperature,
795→                    tx,
796→                )
797→            });
798→
799→            while let Some(event) = rx.recv().await {
800→                let is_done = matches!(event, StreamEvent::Done(_) | StreamEvent::Error(_));
801→                yield event;
802→                if is_done {
803→                    break;
804→                }
805→            }
806→
807→            if let Err(e) = handle.await {
808→                warn!("generation task error: {e}");
809→            }
810→        })
811→    }
812→}
