814→/// Log system info and suggest models on startup.
815→pub fn log_system_info_and_suggestions() {
816→    let sys = system_info::SystemInfo::detect();
817→    let tier = sys.memory_tier();
818→    let cache_dir = models::default_models_dir();
819→
820→    info!(
821→        total_ram_gb = sys.total_ram_gb(),
822→        available_ram_gb = sys.available_ram_gb(),
823→        has_metal = sys.has_metal,
824→        has_cuda = sys.has_cuda,
825→        has_vulkan = sys.has_vulkan,
826→        tier = %tier,
827→        "local-llm system info"
828→    );
829→    info!(
830→        cache_dir = %cache_dir.display(),
831→        "local-llm model cache directory"
832→    );
833→
834→    let backend = if sys.has_metal || sys.is_apple_silicon {
835→        models::ModelBackend::Mlx
836→    } else {
837→        models::ModelBackend::Gguf
838→    };
839→
840→    if let Some(suggested) = models::suggest_model_for_backend(tier, backend) {
841→        info!(
842→            model = suggested.id,
843→            display_name = suggested.display_name,
844→            min_ram_gb = suggested.min_ram_gb,
845→            backend = %backend,
846→            "suggested local model for your system"
847→        );
848→    }
849→
850→    let cached_ids: Vec<&str> = models::MODEL_REGISTRY
851→        .iter()
852→        .filter(|m| models::is_model_cached(m, &cache_dir))
853→        .map(|m| m.id)
854→        .collect();
855→    info!(
856→        cached_models = ?cached_ids,
857→        cached_count = cached_ids.len(),
858→        "cached local models in model cache directory"
859→    );
860→}
