 97→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 98→pub enum MemoryTier {
 99→    /// 4GB or less — only very small models
100→    Tiny,
101→    /// 8GB — small 1-3B models
102→    Small,
103→    /// 16GB — medium 7-14B models
104→    Medium,
105→    /// 32GB+ — larger 14B+ models
106→    Large,
