120→/// Parse `/proc/meminfo` as a fallback when `sysinfo` returns 0 (common in
121→/// Docker containers with restrictive cgroup settings).
122→///
123→/// Returns `(total_bytes, available_bytes)` or `None` if the file is absent or
124→/// unparseable.
125→fn read_proc_meminfo() -> Option<(u64, u64)> {
126→    let content = std::fs::read_to_string("/proc/meminfo").ok()?;
127→    let mut total_kb: Option<u64> = None;
128→    let mut available_kb: Option<u64> = None;
129→
130→    for line in content.lines() {
131→        if let Some(rest) = line.strip_prefix("MemTotal:") {
132→            total_kb = parse_meminfo_kb(rest);
133→        } else if let Some(rest) = line.strip_prefix("MemAvailable:") {
134→            available_kb = parse_meminfo_kb(rest);
135→        }
136→        if total_kb.is_some() && available_kb.is_some() {
137→            break;
138→        }
139→    }
140→
141→    let total = total_kb? * 1024;
142→    let available = available_kb.unwrap_or(0) * 1024;
143→    Some((total, available))
144→}
145→
146→/// Parse a `/proc/meminfo` value line like `"   16384 kB"` into kilobytes.
147→fn parse_meminfo_kb(value: &str) -> Option<u64> {
148→    value.split_whitespace().next()?.parse::<u64>().ok()
149→}
