        assert_eq!(models[1].id, "bartowski/Qwen2.5-Coder-32B-Instruct-GGUF");
        assert_eq!(models[1].downloads, 100000);
        assert!(models[1].created_at.is_none()); // Not all responses have createdAt
    }

