//! Runtime GGUF device probing via llama.cpp.

use {
    llama_cpp_2::{LlamaCppError, list_llama_ggml_backend_devices, llama_backend::LlamaBackend},
    std::sync::OnceLock,
    tracing::debug,
};

/// Global llama backend initialized exactly once, never dropped.
///
/// `LlamaBackend` is an empty struct used only as proof that `llama_backend_init()`
/// was called. By storing it in a `OnceLock` we guarantee:
/// - It is initialized at most once (no `BackendAlreadyInitialized` races).
/// - It is never dropped, so `llama_backend_free()` is never called while model
///   loads or device probes are in flight.
static LLAMA_BACKEND: OnceLock<LlamaBackend> = OnceLock::new();

/// Get a reference to the shared llama backend, initializing it on first call.
///
/// Returns `None` only if `llama_backend_init()` fails with an unexpected error
/// (not `BackendAlreadyInitialized`).
pub(crate) fn shared_backend() -> Option<&'static LlamaBackend> {
    LLAMA_BACKEND
        .get_or_try_init(|| match LlamaBackend::init() {
            Ok(backend) => Ok(backend),
            Err(LlamaCppError::BackendAlreadyInitialized) => {
                // Shouldn't happen with OnceLock, but handle gracefully.
                debug!("llama backend already initialized outside shared_backend");
                Err(())
            },
            Err(error) => {
                debug!(%error, "failed to initialize llama backend");
                Err(())
            },
        })
        .ok()
        .or_else(|| LLAMA_BACKEND.get())
}

