mod tests {
    use super::*;

    #[test]
    fn test_default_config() {
        let config = LocalGgufConfig::default();
        assert!(config.model_id.is_empty());
        assert!(config.model_path.is_none());
        assert_eq!(config.gpu_layers, 0);
        assert!((config.temperature - 0.7).abs() < 0.01);
