        assert!(config.model_path.is_none());
        assert_eq!(config.gpu_layers, 0);
        assert!((config.temperature - 0.7).abs() < 0.01);
    }

    #[test]
    fn test_chat_template_selection() {
        // When model_def is None, should return Auto
