/// Get a reference to the shared llama backend, initializing it on first call.
///
/// Returns `None` only if `llama_backend_init()` fails with an unexpected error
/// (not `BackendAlreadyInitialized`).
pub(crate) fn shared_backend() -> Option<&'static LlamaBackend> {
    // OnceLock guarantees only one thread enters the init closure.
    LLAMA_BACKEND.get_or_init(|| match LlamaBackend::init() {
        Ok(backend) => backend,
        Err(LlamaCppError::BackendAlreadyInitialized) => {
            // Shouldn't happen with OnceLock, but construct a zero-cost proof token.
            debug!("llama backend already initialized outside shared_backend");
            // Backend is already init'd globally; return an empty proof struct.
            // SAFETY: The C backend is already initialized (the error confirms this).
            // LlamaBackend is a zero-sized proof token with no state.
            #[allow(unsafe_code)]
            unsafe {
                std::mem::zeroed()
            }
        },
        Err(error) => {
            debug!(%error, "failed to initialize llama backend");
            // SAFETY: same as above — we need a value to satisfy OnceLock.
            // This path is truly rare (hardware/driver failure).
            #[allow(unsafe_code)]
            unsafe {
                std::mem::zeroed()
            }
        },
    });
    LLAMA_BACKEND.get()
}

