        assert_eq!(make_info(32).memory_tier(), MemoryTier::Large);
        assert_eq!(make_info(64).memory_tier(), MemoryTier::Large);
    }

    #[test]
    fn test_has_gpu() {
        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("Metal")],
            has_metal: true,
            has_cuda: false,
            has_vulkan: false,
            is_apple_silicon: true,
        };
        assert!(info.has_gpu());

        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("CUDA")],
            has_metal: false,
            has_cuda: true,
            has_vulkan: false,
            is_apple_silicon: false,
        };
        assert!(info.has_gpu());

        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("Vulkan")],
            has_metal: false,
            has_cuda: false,
            has_vulkan: true,
            is_apple_silicon: false,
        };
        assert!(info.has_gpu());

        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![],
            has_metal: false,
            has_cuda: false,
            has_vulkan: false,
            is_apple_silicon: false,
        };
        assert!(!info.has_gpu());
    }

    #[test]
    fn test_parse_meminfo_kb() {
        assert_eq!(parse_meminfo_kb("   16384 kB"), Some(16384));
        assert_eq!(parse_meminfo_kb("1024 kB"), Some(1024));
        assert_eq!(parse_meminfo_kb(""), None);
        assert_eq!(parse_meminfo_kb("   not_a_number kB"), None);
    }

    #[test]
    fn test_read_proc_meminfo_on_host() {
        let result = read_proc_meminfo();
        if cfg!(target_os = "linux") {
            let (total, _available) = result.expect("/proc/meminfo should be readable on Linux");
            assert!(total > 0, "total RAM should be > 0");
        } else {
            let _ = result;
        }
    }
}

