            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("Metal")],
            has_metal: true,
            has_cuda: false,
            has_vulkan: false,
            is_apple_silicon: true,
        };
        assert!(info.has_gpu());

        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("CUDA")],
            has_metal: false,
            has_cuda: true,
            has_vulkan: false,
            is_apple_silicon: false,
