        assert!(info.has_gpu());

        let info = SystemInfo {
            total_ram_bytes: 0,
            available_ram_bytes: 0,
            gguf_devices: vec![sample_device("Vulkan")],
            has_metal: false,
            has_cuda: false,
            has_vulkan: true,
            is_apple_silicon: false,
