        gguf_devices: vec![],
        has_metal: false,
        has_cuda: false,
        has_vulkan: false,
        is_apple_silicon: false,
    }
    .gguf_devices
    .into_iter()
    .next()
    .unwrap_or_else(|| unreachable!()));
    sys
}

